# Create customer segments using RFM-like approach
# R = Recency (how recently active - using tenure inversely)
# F = Frequency (using is_active as proxy)
# M = Monetary (monthly_spend_clean)

# Define segments based on business logic
def assign_segment(row):
    spend = row['monthly_spend_clean']
    active = row['is_active']
    tenure_m = row['tenure_months']
    plan = row['plan_tier']

    # High-value segments
    if spend >= 100:
        if active:
            return 'Champions'
        else:
            return 'At Risk High-Value'

    # Medium-high value
    elif spend >= 30:
        if active:
            return 'Loyal Customers'
        else:
            return 'Need Attention'

    # Medium value
    elif spend >= 10:
        if active:
            if tenure_m < 6:
                return 'Promising'
            else:
                return 'Potential Loyalists'
        else:
            return 'About to Sleep'

    # Low/no spend
    else:
        if active:
            if tenure_m < 3:
                return 'New Users'
            elif plan == 'free':
                return 'Free Riders'
            else:
                return 'Hibernating'
        else:
            return 'Lost'

df['segment'] = df.apply(assign_segment, axis=1)

print("Segment distribution:")
print(df['segment'].value_counts())
print("\nSegment characteristics:")
segment_summary = df.groupby('segment').agg({
    'monthly_spend_clean': ['mean', 'median', 'sum'],
    'is_active': 'mean',
    'tenure_months': 'mean',
    'user_id': 'count'
}).round(2)
print(segment_summary)
